@Composable
private fun ContextPanel(
    label: String,
    value: String,
    supportingValue: String,
    facts: List<Pair<String, String>>,
    theme: MaterialThemePalette,
    onReloadContext: () -> Unit,
    isReloading: Boolean,
) {
    var isReloadPressed by remember { mutableStateOf(false) }

    Div(
        attrs = {
            style {
                display(DisplayStyle.Flex)
                flexDirection(FlexDirection.Column)
                gap(4.px)
                padding(12.px, 14.px)
                borderRadius(18.px)
                property("min-width", "220px")
                property("background", theme.surfaceContainer)
                property("border", "1px solid ${theme.outlineVariant}")
                property("box-shadow", "inset 0 1px 0 ${theme.scrim}")
            }
        }
    ) {
        Div(
            attrs = {
                style {
                    display(DisplayStyle.Flex)
                    property("justify-content", "space-between")
                    property("align-items", "center")
                    property("gap", "8px")
                }
            }
        ) {
            P(
                attrs = {
                    style {
                        margin(0.px)
                        property("color", theme.onSurfaceVariant)
                        property("font-size", "0.72rem")
                        property("font-weight", "700")
                        property("letter-spacing", "0.1em")
                        property("text-transform", "uppercase")
                    }
                }
            ) {
                Text(label)
            }

            Button(
                attrs = {
                    attr("title", if (isReloading) "Loading..." else "Reload context")
                    attr("aria-label", if (isReloading) "Loading context" else "Reload context")
                    onClick { if (!isReloading) onReloadContext() }
                    onMouseDown { if (!isReloading) isReloadPressed = true }
                    onMouseUp { isReloadPressed = false }
                    onMouseLeave { isReloadPressed = false }
                    style {
                        padding(4.px, 8.px)
                        borderRadius(10.px)
                        property("background", "transparent")
                        property("border", "none")
                        property("color", theme.onSurfaceVariant)
                        property("font-size", "0.72rem")
                        property("font-weight", "600")
                        property("cursor", if (isReloading) "default" else "pointer")
                        property("opacity", if (isReloading) "0.45" else if (isReloadPressed) "0.7" else "0.6")
                        property("transition", "opacity 120ms ease")
                        property("touch-action", "manipulation")
                        property("user-select", "none")
                    }
                }
            ) {
                Text(if (isReloading) "↻ Loading" else "↻ Reload")
            }
        }

        P(
            attrs = {
                style {
                    margin(0.px)
                    property("font-size", "0.92rem")
                    property("font-weight", "650")
                }
            }
        ) {
            Text(value)
        }
        P(
            attrs = {
                style {
                    margin(0.px)
                    property("font-size", "0.84rem")
                    property("color", theme.onSurfaceVariant)
                    property("line-height", "1.45")
                }
            }
        ) {
            Text(supportingValue)
        }

        if (facts.isNotEmpty()) {
            Div(
                attrs = {
                    style {
                        display(DisplayStyle.Flex)
                        property("flex-wrap", "wrap")
                        gap(8.px)
                        property("margin-top", "4px")
                    }
                }
            ) {
                facts.forEach { (label, value) ->
                    ContextFactChip(label = label, value = value, theme = theme)
                }
            }
        }
    }
}

private fun districtFacts(district: SelectedDistrictContext): List<Pair<String, String>> =
    listOfNotNull(
        district.city?.let { "City" to it },
        district.state?.let { "State" to it },
        district.county?.let { "County" to it },
        district.timezone?.let { "Timezone" to it },
        district.defaultTaxRateBps?.let { "Sales Tax" to formatTaxRatePercent(it) },
    )

private fun schoolFacts(school: SelectedSchoolContext): List<Pair<String, String>> =
    listOfNotNull(
        school.shortName?.takeIf(String::isNotBlank)?.let { "Short Name" to it },
        "Status" to if (school.active) "Active" else "Inactive",
    )

@Composable
private fun ContextFactChip(
    label: String,
    value: String,
    theme: MaterialThemePalette,
) {
    Div(
        attrs = {
            style {
                display(DisplayStyle.Flex)
                property("align-items", "center")
                gap(6.px)
                padding(8.px, 10.px)
                borderRadius(14.px)
                property("background", theme.surfaceVariant)
                property("border", "1px solid ${theme.outlineVariant}")
            }
        }
    ) {
        P(
            attrs = {
                style {
                    margin(0.px)
                    property("font-size", "0.7rem")
                    property("font-weight", "700")
                    property("letter-spacing", "0.08em")
                    property("text-transform", "uppercase")
                    property("color", theme.onSurfaceVariant)
                }
            }
        ) {
            Text(label)
        }
        P(
            attrs = {
                style {
                    margin(0.px)
                    property("font-size", "0.82rem")
                    property("font-weight", "600")
                    property("color", theme.onSurface)
                }
            }
        ) {
            Text(value)
        }
    }
}

private fun List<AdminRoute>.coerceAtLeastOne(): List<AdminRoute> =
    if (isEmpty()) listOf(AdminRoute.Settings) else this
